  public useFilter(
    filtro: FilterOperador,
    voiceCommand?: ICommandSpeakerRequest,
  ) {
    const request: IFilterOperadorWithVoiceRequest = {
      filter: filtro || new FilterOperadorDefaults(),
      voiceCommand: voiceCommand,
    };

    const url = `${this.baseUrl}/Filter/${this.uri}`;
    const key = `${url}::${this.authorization}::${JSON.stringify(request)}`;

    return useSWR<Operador[]>(key, fetcher, {
      revalidateOnFocus: false,
      revalidateOnReconnect: false,
      shouldRetryOnError: false,
      onErrorRetry: (error, _key, _config, revalidate, { retryCount }) => {
        // Não retenta em erros 4xx (exceto 408/429)
        if (
          error?.status &&
          error.status >= 400 &&
          error.status < 500 &&
          error.status !== 408 &&
          error.status !== 429
        )
          return;
        // Máximo 3 tentativas
        if (retryCount >= 3) return;
        setTimeout(
          () => revalidate({ retryCount }),
          Math.min(1000 * 2 ** retryCount, 30000),
        );
      },
      onError: (error) => {
        if (process.env.NEXT_PUBLIC_SHOW_LOG === "1")
          console.log("Erro no SWR para filtro de Operador:", error);
        this.notificationService.notify({
          entity: "Operador",
          id: 0,
          action: NotifySystemActions.ERROR,
          message: "Erro ao carregar dados dos Operador",
        });
      },
    });
  }
